// // This module implements a 16-bit register with disable. When the disable input is low, the register captures the value of the 16-bit input 'd' on the falling edge of the clock. The reset input is active low asynchronous, and should set the output to 16'hFFFF_FFFF.
module register_with_enable(
	input clk,
	input reset,
	input enable,
	input [15:0] d,
	output reg [15:0] q);always @(posedge clk)
	if (reset)
		q <= 16'b0000000000000000;
	else if (enable)
		q <= d;

endmodule
